import React, { useState, useEffect, useCallback } from 'react'
import useData from './data';
import { useTableContext } from './Provider';
import useIntersectionObserver from './useIntersectionObserver';

function InfiniteScroll({ children }) {
    const [page, setPage] = useState(0)
    const { loading, error, tableData, total } = useData(page)
    const { setTableData, searchedData } = useTableContext()

    const hasMore = searchedData ? searchedData.length < total : false

    // Push fetched page data into context
    useEffect(() => {
        if (tableData) {
            setTableData(tableData)
        }
    }, [tableData])

    // Increment page when sentinel comes into view
    const loadMore = useCallback(() => {
        if (!loading && hasMore) {
            setPage(prev => prev + 1)
        }
    }, [loading, hasMore])

    const loaderRef = useIntersectionObserver(loadMore, { threshold: 0.1 }, hasMore && !loading)

    return (
        <>
            {children}
            <div ref={loaderRef}>
                {loading && 'Loading...'}
            </div>
        </>
    )
}

export default InfiniteScroll
